func (ll *LinkedList[T]) ToSlice() []T {
	result := make([]T, 0, ll.size)
	current := ll.Head
	for current != nil {
		result = append(result, current.Value)
		current = current.Next
	}
	return result
}

func (ll *LinkedList[T]) Prepend(value T) {
	node := &LinkedListNode[T]{Value: value, Next: ll.Head}
	ll.Head = node
	if ll.Tail == nil {
		ll.Tail = node
	}
	ll.size++
}

func (p Pair[T, U]) Swap() Pair[U, T] {
	return Pair[U, T]{First: p.Second, Second: p.First}
}

func (ll *LinkedList[T]) Append(value T) {
	node := &LinkedListNode[T]{Value: value}
	if ll.Head == nil {
		ll.Head = node
		ll.Tail = node
	} else {
		ll.Tail.Next = node
		ll.Tail = node
	}
	ll.size++
}

func Reduce[T any, U any](items []T, initial U, fn func(U, T) U) U {
	result := initial
	for _, item := range items {
		result = fn(result, item)
	}
	return result
}

func Map[T any, U any](items []T, fn func(T) U) []U {
	result := make([]U, len(items))
	for i, item := range items {
		result[i] = fn(item)
	}
	return result
}

func demonstrateGenerics() {
	// Generic functions
	fmt.Println("Max:", GenericMax(10, 20))
	fmt.Println("Max:", GenericMax(3.14, 2.71))

	// Generic stack
	stack := Stack[int]{}
	stack.Push(1)
	stack.Push(2)
	stack.Push(3)
	val, _ := stack.Pop()
	fmt.Println("Popped:", val)

	// Generic map/filter/reduce
	numbers := []int{1, 2, 3, 4, 5}
	doubled := Map(numbers, func(n int) int { return n * 2 })
	fmt.Println("Doubled:", doubled)

	evens := Filter(numbers, func(n int) bool { return n%2 == 0 })
	fmt.Println("Evens:", evens)

	sum := Reduce(numbers, 0, func(acc, n int) int { return acc + n })
	fmt.Println("Sum:", sum)

	// Generic cache
	cache := NewCache[string, int]()
	cache.Set("age", 30)
	age, _ := cache.Get("age")
	fmt.Println("Age:", age)
}

