func Pipeline(numbers []int) []int {
	stage1 := make(chan int)
	stage2 := make(chan int)

	// Input
	go func() {
		for _, num := range numbers {
			stage1 <- num
		}
		close(stage1)
	}()

	// Stage 1
	go PipelineStage1(stage1, stage2)

	// Collect results
	var results []int
	for result := range stage2 {
		results = append(results, result)
	}

	return results
}

