    if !email.contains('@') {
        return Err(ValidationError {
            field: "email".to_string(),
            value: email.to_string(),
            reason: "Must contain @ symbol".to_string(),
        });
    }
    if !email.contains('.') {
        return Err(ValidationError {
            field: "email".to_string(),
            value: email.to_string(),
            reason: "Must contain domain extension".to_string(),
        });
    }
    Ok(email.to_string())
}

