fn next(&mut self) -> Option<Self::Item> {
        if self.remainder.is_empty() {
            return None;
        }

        match self.remainder.find(self.delimiter) {
            Some(pos) => {
                let result = &self.remainder[..pos];
                self.remainder = &self.remainder[pos + 1..];
                Some(result)
            }
            None => {
                let result = self.remainder;
                self.remainder = "";
                Some(result)
            }
        }
    }

