function createTypeSafeGetter<T>() {
  return function get<K extends Paths<T>>(obj: T, path: K): Get<T, K> {
    const keys = path.split('.') as string[];
    let result: any = obj;

    for (const key of keys) {
      result = result?.[key];
    }

    return result as Get<T, K>;
  };
}

