function sortBy<T, K extends keyof T = keyof T>(
  array: T[],
  key: K,
  ascending: boolean = true
): T[] {
  return array.sort((a, b) => {
    const valueA = a[key];
    const valueB = b[key];

    if (valueA < valueB) return ascending ? -1 : 1;
    if (valueA > valueB) return ascending ? 1 : -1;
